-- Chien -> humain, Fête, Volume 5

insert into public.message_templates (user_id,title,content,tone,is_system,is_manual_only,occasion,animal_type,animal_direction) values

(null,'Joyeuse fête. J''ai observé ta façon de ranger les bouteilles vides.',$$Joyeuse fête. J''ai observé ta façon de ranger les bouteilles vides.
Tu les mets de côté proprement. En ligne. Avec un ordre qui dit que même les bouteilles vides méritent d''être traitées avec soin. Pas jetées n''importe comment. Posées. Cette façon de traiter ce qui a servi. Ce soin pour les choses finies. Joyeuse fête, mon humain préféré.
Avec observation de ton soin pour les bouteilles vides et ce qu''il dit sur ta nature, — {prenom}, ton animal attentif à ta façon de traiter ce qui a servi 🍾$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. J''ai observé comment tu introduis deux personnes qui ne se connaissent pas.',$$Joyeuse fête. J''ai observé comment tu introduis deux personnes qui ne se connaissent pas.
Tu dis le prénom de l''un. Puis le prénom de l''autre. Puis tu ajoutes quelque chose qui pourrait les connecter. Un point commun. Un sujet commun. Et tu les laisses prendre le relais. Cette façon de créer des liens. De tisser ta soirée. Joyeuse fête, mon humain préféré.
Avec admiration pour ton art de tisser les liens entre tes invités, — {prenom}, ton animal témoin de ton architecture sociale 🤝$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. Je comprends pas pourquoi les gens arrivent différemment seuls ou en couple.',$$Joyeuse fête. Je comprends pas pourquoi les gens arrivent différemment seuls ou en couple.
Seuls ils sonnent et attendent. En couple ils sonnent et il y a déjà une conversation entre eux quand tu ouvres. Comme si venir à deux signifiait qu''on apporte déjà de la vie dans la fête. Les deux ont leur charme. Joyeuse fête, mon humain préféré.
Avec analyse des modes d''arrivée selon la configuration et leurs implications sociales, — {prenom}, ton animal sociologue des arrivées 🚶$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. J''ai mémorisé les moments où tu as regardé l''heure.',$$Joyeuse fête. J''ai mémorisé les moments où tu as regardé l''heure.
Six fois. Six regards discrets vers l''heure. Pour vérifier que le repas serait prêt au bon moment. Que les gens n''allaient pas partir trop tôt. Que la soirée avançait bien. Ces six regards temporels dans le flux de la fête. Joyeuse fête, mon humain préféré.
Avec six regards vers l''heure comptés et leur signification de soin temporel établie, — {prenom}, ton animal gardien du tempo de tes fêtes ⌚$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. J''ai observé ta façon de couper le pain.',$$Joyeuse fête. J''ai observé ta façon de couper le pain.
Des tranches égales. Tu les comptes mentalement. Tu t''assures qu''il y en aura assez pour tout le monde. Tu poses les tranches avec soin dans la corbeille. Ce geste simple qui dit que tu penses à tout. Que tu anticipes les besoins. Que personne ne manquera de pain. Joyeuse fête, mon humain préféré.
Avec observation de ton soin en tranches et sa signification d''attention pour chacun, — {prenom}, ton animal expert en petits gestes qui comptent 🍞$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. J''ai observé comment tu gères quelqu''un qui ne mange pas ce que tu as cuisiné.',$$Joyeuse fête. J''ai observé comment tu gères quelqu''un qui ne mange pas ce que tu as cuisiné.
Tu ne forces pas. Tu proposes autre chose. Tu t''assures qu''il y a quelque chose pour tout le monde. Pas de remarque. Pas de déception visible. Juste une adaptation silencieuse et généreuse. Joyeuse fête, mon humain préféré.
Avec admiration pour ta gestion sans jugement des préférences alimentaires des autres, — {prenom}, ton animal témoin de ta générosité inclusive 🥗$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. Je comprends pas pourquoi les gens parlent de la météo même en fête.',$$Joyeuse fête. Je comprends pas pourquoi les gens parlent de la météo même en fête.
Dehors il fait quelque chose. Dedans il fait une fête. Et pourtant la conversation sur ce qu''il fait dehors revient. Peut-être que la météo est le sujet universel qui peut relier n''importe qui. Joyeuse fête, mon humain préféré.
Avec compréhension de la météo comme conversation refuge et respect pour son utilité, — {prenom}, ton animal qui a ses propres sujets universels 🌦️$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. J''ai étudié ta façon de plier les serviettes.',$$Joyeuse fête. J''ai étudié ta façon de plier les serviettes.
Pas origami. Juste plié proprement. Avec un geste rapide qui dit que tu l''as fait des centaines de fois. Que la serviette bien pliée c''est une évidence. Ce détail invisible que les invités voient sans voir. Qui dit quelque chose sur le soin qu''on a mis dans l''ensemble. Joyeuse fête, mon humain préféré.
Avec observation de tes serviettes pliées et leur signification de soin général de la soirée, — {prenom}, ton animal expert en détails invisibles 🍽️$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. J''ai observé ta façon de sortir les plats du four.',$$Joyeuse fête. J''ai observé ta façon de sortir les plats du four.
Avec les gants épais. La posture légèrement courbée. La précaution dans le mouvement. Cette danse autour du chaud. Ces gestes que tu as développés au fil des années. Une chorégraphie de cuisine que tu ne sais plus que tu sais. Joyeuse fête, mon humain préféré.
Avec observation de ta chorégraphie four-gants et admiration pour ses automatismes, — {prenom}, ton animal spectateur de tes gestes appris 🧤$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. J''ai observé comment tu changes d''attitude quand tu es fatigué mais que la fête continue.',$$Joyeuse fête. J''ai observé comment tu changes d''attitude quand tu es fatigué mais que la fête continue.
Il y a eu un moment. Vers 22h. Où j''ai vu la fatigue passer sur ton visage une seconde. Puis tu t''es repris. Tu as pris une gorgée. Tu as souri. Tu es revenu. Cette façon de puiser dans une réserve qu''on ne savait pas avoir. Joyeuse fête, mon humain préféré.
Avec observation de ta reprise à 22h et admiration pour ta réserve de présence, — {prenom}, ton animal témoin de tes ressources cachées 💪$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. Je comprends pas pourquoi les gens sortent leurs téléphones en même temps.',$$Joyeuse fête. Je comprends pas pourquoi les gens sortent leurs téléphones en même temps.
À certains moments ce soir plusieurs téléphones sont sortis simultanément. Comme un signal invisible. Comme si une fréquence commune avait décidé que c''était le moment de vérifier. Ce comportement synchronisé sans coordination. Fascinant. Joyeuse fête, mon humain préféré.
Avec fascination pour la synchronisation téléphonique involontaire et mystère persistant, — {prenom}, ton animal chercheur en comportements grégaires numériques 📱$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. J''ai mémorisé ta façon d''articuler quand tu racontes quelque chose d''important.',$$Joyeuse fête. J''ai mémorisé ta façon d''articuler quand tu racontes quelque chose d''important.
Ta voix ralentit légèrement. Chaque mot prend un peu plus de place. Tes mains bougent différemment. Ton regard cherche si les gens suivent vraiment. Ce changement de rythme pour les choses importantes. Joyeuse fête, mon humain préféré.
Avec mémorisation de tes signaux d''importance narrative et leur précision, — {prenom}, ton animal linguiste de tes variations de rythme 🗣️$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. J''ai observé ta façon de vérifier que les bougies sont bien droites avant de les allumer.',$$Joyeuse fête. J''ai observé ta façon de vérifier que les bougies sont bien droites avant de les allumer.
Tu les ajustes. Une par une. Tu regardes l''ensemble. Tu en redresses une. Tu recules pour voir. Cette précision pour quelque chose qui va brûler et disparaître en quelques minutes. Ce soin pour l''éphémère. C''est beau. C''est toi. Joyeuse fête, mon humain préféré.
Avec admiration pour ton soin accordé à l''éphémère et ce qu''il dit sur ta façon d''être, — {prenom}, ton animal philosophe du soin pour ce qui dure peu 🕯️$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. J''ai observé comment tu t''excuses quand quelque chose n''est pas parfait.',$$Joyeuse fête. J''ai observé comment tu t''excuses quand quelque chose n''est pas parfait.
Tu t''excuses. Brièvement. Honnêtement. Sans surjouer. Et tu passes à autre chose. Tu ne te noies pas dans l''excuse. Tu mentionnes et tu continues. C''est de la grâce. Joyeuse fête, mon humain préféré.
Avec observation de ton art de l''excuse brève et de la reprise, — {prenom}, ton animal admirateur de ta grâce face à l''imperfection 🙏$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. Je comprends pas pourquoi les gens parlent de leurs vacances à chaque fête.',$$Joyeuse fête. Je comprends pas pourquoi les gens parlent de leurs vacances à chaque fête.
C''est revenu ce soir. Les vacances. Où on est allé. Qu''est-ce qu''on a vu. Chaque fête semble être une occasion de faire le bilan des déplacements récents. Moi je me déplace dans l''appartement. C''est mes vacances. Mais je reconnais l''intérêt de l''échange. Joyeuse fête, mon humain préféré.
Avec compréhension de l''échange de récits de voyages et solidarité de mes propres explorations locales, — {prenom}, ton animal voyageur de l''appartement 🗺️$$,'touching',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. J''ai étudié la façon dont tu disposes les choses sur le buffet.',$$Joyeuse fête. J''ai étudié la façon dont tu disposes les choses sur le buffet.
Rien n''est au hasard. Les choses hautes au fond. Les petites devant. Les couleurs pensées. Les textures variées. Ce buffet c''est une composition. Une œuvre collective qui dit qu''on a pensé à l''ensemble. Joyeuse fête, mon humain préféré, dont le buffet est de l''art appliqué.
Avec admiration pour ta composition de buffet et sa logique esthétique et pratique, — {prenom}, ton animal critique du buffet et de ses équilibres 🎨$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. J''ai observé ta façon de sourire quand quelqu''un goûte quelque chose que tu as préparé.',$$Joyeuse fête. J''ai observé ta façon de sourire quand quelqu''un goûte quelque chose que tu as préparé.
Cette fraction de seconde. Entre le moment où la fourchette entre dans la bouche et le moment où le verdict paraît. Toi pendant ce temps tu regardes. Discrètement. Et quand le sourire arrive sur leur visage le tien suit. Joyeuse fête, mon humain préféré.
Avec observation de ta fraction de seconde d''attente et de son aboutissement en sourire partagé, — {prenom}, ton animal gardien de tes moments de validation 😊$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. J''ai observé comment tu gères une conversation qui t''ennuie.',$$Joyeuse fête. J''ai observé comment tu gères une conversation qui t''ennuie.
Tu écoutes. Tu hoches la tête. Tu poses une question de relance. Mais ton regard fait de petits voyages. Et à un moment tu trouves une sortie élégante. Tu passes à autre chose sans que l''autre ne le ressente. Joyeuse fête, mon humain préféré.
Avec admiration pour ta gestion de l''ennui conversationnel sans jamais le montrer, — {prenom}, ton animal expert en politesse de façade sincère 😌$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. Je comprends pas pourquoi les gens disent qu''ils ne boivent pas et boivent quand même.',$$Joyeuse fête. Je comprends pas pourquoi les gens disent qu''ils ne boivent pas et boivent quand même.
C''est arrivé deux fois ce soir. Je ne bois pas ou presque. Puis une coupe pour le toast. Puis un verre pour accompagner. Peut-être que les fêtes ont leurs propres règles. Je médite ça. Joyeuse fête, mon humain préféré.
Avec méditation sur la relativité des résolutions face aux occasions festives, — {prenom}, ton animal philosophe des exceptions 🥂$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. J''ai mémorisé chaque fois que tu as ri sans retenue ce soir.',$$Joyeuse fête. J''ai mémorisé chaque fois que tu as ri sans retenue ce soir.
Quatre fois. Quatre moments où le rire est sorti vraiment. Sans filtre. Avec les yeux qui plissent et la tête qui part. Ces quatre moments sont les meilleurs de la soirée. Ils disent que tu étais vraiment là. Vraiment bien. Vraiment toi. Joyeuse fête, mon humain préféré.
Avec quatre rires sans retenue mémorisés et leur valeur placée au-dessus de tout, — {prenom}, ton animal collectionneur de tes moments de liberté 😂$$,'humorous',true,false,'nameday','chien','from')

on conflict do nothing;
